```

NEW:
```rust
// Convert sRGB u8 palette values to linear f64 for wgpu clear color.
// Formula: linear = (srgb / 255.0)^2.2 (approx) or use proper sRGB curve.
fn srgb_to_linear(v: f32) -> f64 {
    if v <= 0.04045 { (v / 12.92) as f64 }
    else { ((v + 0.055) / 1.055_f32).powf(2.4) as f64 }
}
