```

2. In the LauncherSurface constructor (main() around line 182), initialize:
```rust
cached_query_buf: None,
cached_entry_bufs: Vec::new(),
cached_query: String::new(),
cached_results: Vec::new(),
```

3. At the start of render_frame() (line ~513), replace the buffer allocation block with:
```rust
let query_dirty = self.state.query != self.cached_query;
let results_dirty = self.state.results != self.cached_results;
if query_dirty {
    // rebuild query_buf only
    let mut buf = Buffer::new(...);
    // ... set text ...
    self.cached_query_buf = Some(buf);
    self.cached_query = self.state.query.clone();
